import { crackSafe } from '../0753-cracking-the-safe.js';

describe('0753-cracking-the-safe', () => {
  it("crackSafe(1, 1)", () => {
    const result = crackSafe(1, 1);
    expect(result).toEqual("0");
  });

  it("crackSafe(0, 0)", () => {
    const result = crackSafe(0, 0);
    expect(result).toEqual("");
  });

  it("crackSafe(3, 7)", () => {
    const result = crackSafe(3, 7);
    expect(result).toEqual("");
  });
});
